import java.io.*;
import org.antlr.v4.runtime.*;
import org.antlr.v4.runtime.tree.*;
import org.antlr.v4.gui.*;
import aufgabe2.aufgabe2ab.bestellungsparser;
import aufgabe2.aufgabe2ab.bestellungslexer;

public class SimpleTestRig {
    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.out.println("Usage: java SimpleTestRig <input-text> [-gui|-tree|-tokens]");
            System.exit(1);
        }

        String input = args[0];
        String mode = args.length > 1 ? args[1] : "-tree";

        // Lex and parse
        CharStream chars = CharStreams.fromString(input);
        bestellungslexer lexer = new bestellungslexer(chars);
        CommonTokenStream tokens = new CommonTokenStream(lexer);
        bestellungsparser parser = new bestellungsparser(tokens);

        // Show tokens if requested
        if (mode.equals("-tokens")) {
            tokens.fill();
            System.out.println("=== TOKENS ===");
            for (Object token : tokens.getTokens()) {
                System.out.println(token);
            }
            System.out.println();
        }

        // Parse
        bestellungsparser.BestellungContext tree = parser.bestellung();

        // Show tree
        if (mode.equals("-tree")) {
            System.out.println("=== PARSE TREE ===");
            System.out.println(tree.toStringTree(parser));
        }

        // GUI
        if (mode.equals("-gui")) {
            java.util.Arrays.asList(parser.getRuleNames());
            TreeViewer viewer = new TreeViewer(java.util.Arrays.asList(parser.getRuleNames()), parser.getATN());
            viewer.show((ParseTree)tree);
        }
    }
}

import java.io.*;
import org.antlr.v4.runtime.*;
import aufgabe2.aufgabe2ab.bestellungsparser;
import aufgabe2.aufgabe2ab.bestellungslexer;

public class SimpleTestRig {
    public static void main(String[] args) throws Exception {
        try {
            // Read from stdin
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            StringBuilder sb = new StringBuilder();
            String line;
            while ((line = reader.readLine()) != null) {
                sb.append(line);
            }
            String input = sb.toString().trim();

            if (input.isEmpty()) {
                System.err.println("No input provided");
                System.exit(1);
            }

            // Lex and parse
            CharStream chars = CharStreams.fromString(input);
            bestellungslexer lexer = new bestellungslexer(chars);
            CommonTokenStream tokens = new CommonTokenStream(lexer);
            bestellungsparser parser = new bestellungsparser(tokens);

            // Parse
            bestellungsparser.BestellungContext tree = parser.bestellung();

            // Show tree
            System.out.println(tree.toStringTree(parser));
        } catch (Exception e) {
            System.err.println("Error: " + e.getMessage());
            e.printStackTrace();
            System.exit(1);
        }
    }
}
